import{_ as o,C as n,o as l,c as s,E as a,w as e,a as r,a0 as d}from"./chunks/framework.CkNTPv-z.js";const b=JSON.parse('{"title":"Moving to Latvia","description":"Immigration pathways and relocation guide for Latvia","frontmatter":{"layout":"doc","title":"Moving to Latvia","description":"Immigration pathways and relocation guide for Latvia"},"headers":[],"relativePath":"europe/latvia/moving-there.md","filePath":"europe/latvia/moving-there.md","lastUpdated":null}'),h={name:"europe/latvia/moving-there.md"};function g(u,t,m,c,f,v){const i=n("Badge");return l(),s("div",null,[a(i,{variant:"green"},{default:e(()=>[...t[0]||(t[0]=[r("EU: Free Movement",-1)])]),_:1}),a(i,{variant:"yellow"},{default:e(()=>[...t[1]||(t[1]=[r("Non-EU: Work Visa",-1)])]),_:1}),a(i,{variant:"yellow"},{default:e(()=>[...t[2]||(t[2]=[r("No Specific DN Visa",-1)])]),_:1}),t[3]||(t[3]=d('<h1 id="moving-to-latvia" tabindex="-1">Moving to Latvia <a class="header-anchor" href="#moving-to-latvia" aria-label="Permalink to &quot;Moving to Latvia&quot;">​</a></h1><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">​</a></h2><h3 id="eea-eu-citizens" tabindex="-1">EEA/EU Citizens <a class="header-anchor" href="#eea-eu-citizens" aria-label="Permalink to &quot;EEA/EU Citizens&quot;">​</a></h3><ul><li><strong>Free movement rights</strong> — no visa required</li><li><strong>Up to 3 months</strong>: No registration needed</li><li><strong>Over 3 months</strong>: Register with the Office of Citizenship and Migration Affairs (PMLP)</li><li><strong>Right to work</strong>: Automatic</li><li><strong>Population Register</strong>: Must register your place of residence</li></ul><h3 id="uk-citizens-post-brexit" tabindex="-1">UK Citizens (Post-Brexit) <a class="header-anchor" href="#uk-citizens-post-brexit" aria-label="Permalink to &quot;UK Citizens (Post-Brexit)&quot;">​</a></h3><ul><li><strong>Schengen Area</strong>: Visa-free for up to 90 days in any 180-day period</li><li><strong>Long-term residency</strong>: Requires a residence permit: <ul><li>Work permit (job offer from Latvian employer)</li><li>Student visa (enrollment at Latvian university)</li><li>Family reunification</li><li>Real estate visa (€250,000+ property investment)</li></ul></li></ul><h3 id="third-country-nationals" tabindex="-1">Third-Country Nationals <a class="header-anchor" href="#third-country-nationals" aria-label="Permalink to &quot;Third-Country Nationals&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visa Type</th><th>Requirements</th><th>Duration</th></tr></thead><tbody><tr><td>Work Permit</td><td>Job offer from Latvian employer</td><td>Up to 2 years, renewable</td></tr><tr><td>Student Visa</td><td>Enrollment at accredited institution</td><td>Duration of studies</td></tr><tr><td>Family Reunification</td><td>Family ties to Latvian resident</td><td>Tied to sponsor&#39;s status</td></tr><tr><td>Real Estate Visa</td><td>€250,000+ property investment</td><td>5 years, renewable</td></tr><tr><td>Start-up Visa</td><td>Innovative business idea</td><td>Up to 2 years</td></tr></tbody></table><h2 id="digital-nomad-remote-work" tabindex="-1">Digital Nomad / Remote Work <a class="header-anchor" href="#digital-nomad-remote-work" aria-label="Permalink to &quot;Digital Nomad / Remote Work&quot;">​</a></h2><p>Latvia does <strong>not have a dedicated digital nomad visa</strong>. Remote workers can consider:</p><ul><li><strong>Work visa</strong> if employed by a Latvian company</li><li><strong>Start-up visa</strong> for entrepreneurs</li><li><strong>Temporary residence permit</strong> through real estate investment</li><li>Some remote workers enter on a 90-day tourist visa for short stays, but this does not permit work</li></ul><h2 id="moving-checklist" tabindex="-1">Moving Checklist <a class="header-anchor" href="#moving-checklist" aria-label="Permalink to &quot;Moving Checklist&quot;">​</a></h2><h3 id="before-moving" tabindex="-1">Before Moving <a class="header-anchor" href="#before-moving" aria-label="Permalink to &quot;Before Moving&quot;">​</a></h3><ul><li>[ ] <strong>Passport</strong>: Valid for duration of stay</li><li>[ ] <strong>Visa</strong>: Apply 2-3 months in advance</li><li>[ ] <strong>Healthcare</strong>: Private health insurance required initially; register with NVD after residency</li><li>[ ] <strong>HRT</strong>: Get 6-month supply and doctor&#39;s letter (translated to Latvian)</li><li>[ ] <strong>Banking</strong>: Consider Swedbank, SEB, or Citadele</li><li>[ ] <strong>Housing</strong>: Research rental market (ss.lv, city24.lv)</li><li>[ ] <strong>Language</strong>: Latvian essential for daily life; Russian widely spoken</li><li>[ ] <strong>Document translation</strong>: Official Latvian translations of key documents needed</li></ul><h3 id="after-arrival" tabindex="-1">After Arrival <a class="header-anchor" href="#after-arrival" aria-label="Permalink to &quot;After Arrival&quot;">​</a></h3><ul><li>[ ] Register with PMLP (Office of Citizenship and Migration Affairs)</li><li>[ ] Obtain personal code (Personas kods) — essential for all services</li><li>[ ] Register for healthcare (NVD — National Health Service)</li><li>[ ] Open local bank account</li><li>[ ] Get local SIM card (LMT, Tele2, Bite)</li><li>[ ] Connect with LGBTQ+ community (Mozaika, Baltic Pride)</li><li>[ ] Find a GP and endocrinologist for HRT continuation</li></ul><h2 id="practical-information" tabindex="-1">Practical Information <a class="header-anchor" href="#practical-information" aria-label="Permalink to &quot;Practical Information&quot;">​</a></h2><h3 id="cost-of-living" tabindex="-1">Cost of Living <a class="header-anchor" href="#cost-of-living" aria-label="Permalink to &quot;Cost of Living&quot;">​</a></h3><ul><li><strong>Low to moderate</strong> — one of the cheaper EU countries</li><li>Monthly rent (1-bed): €300-600 (Riga), €200-400 (other cities)</li><li>Monthly groceries: €250-350</li><li>Public transport: €30/month (Riga)</li><li>Dining out: €8-15 per meal</li></ul><h3 id="best-cities-for-lgbtq-community" tabindex="-1">Best Cities for LGBTQ+ Community <a class="header-anchor" href="#best-cities-for-lgbtq-community" aria-label="Permalink to &quot;Best Cities for LGBTQ+ Community&quot;">​</a></h3><table tabindex="0"><thead><tr><th>City</th><th>LGBTQ+ Scene</th><th>Trans Healthcare</th></tr></thead><tbody><tr><td><strong>Riga</strong></td><td>Moderate (few bars, venues)</td><td>Limited (RAKUS)</td></tr><tr><td><strong>Daugavpils</strong></td><td>Very limited</td><td>None</td></tr><tr><td><strong>Jurmala</strong></td><td>Very limited</td><td>None</td></tr></tbody></table><h3 id="climate" tabindex="-1">Climate <a class="header-anchor" href="#climate" aria-label="Permalink to &quot;Climate&quot;">​</a></h3><ul><li><strong>Winters</strong>: Cold (-5°C to -15°C), snow common, limited daylight (6-7 hours)</li><li><strong>Summers</strong>: Mild (15-25°C), long daylight</li><li><strong>Spring/Autumn</strong>: Transitional, rainy</li></ul><h3 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h3><ul><li>Official language: Latvian</li><li>Russian: Very widely spoken (approx. 37% native speakers)</li><li>English: Limited outside Riga and younger generations</li><li>Free Latvian language courses available for immigrants</li><li>Russian is very useful for daily life, especially outside Riga</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.pmlp.gov.lv/" target="_blank" rel="noreferrer">PMLP (Office of Citizenship and Migration)</a></li><li><a href="https://www.vmnvd.gov.lv/" target="_blank" rel="noreferrer">NVD (National Health Service)</a></li><li><a href="https://www.latvia.eu/" target="_blank" rel="noreferrer">Latvia.lv - Immigration</a></li><li><a href="https://www.mozaika.lv/" target="_blank" rel="noreferrer">Mozaika (LGBTQ+ Organization)</a></li><li><a href="https://www.baltipride.com/" target="_blank" rel="noreferrer">Baltic Pride</a></li></ul>',27))])}const y=o(h,[["render",g]]);export{b as __pageData,y as default};
